const FAQ = () => {
	return (
		<div className={styles.FAQ} id='faq-section'>
			<div className={`${styles.container} container`}>
				<div className={styles.wrapper}>
					<h2 className={styles.title}>Частые вопросы</h2>
					<ul className={styles.list}>
						<li className={styles.item}>
							<div className={styles.iconWrapper}>{firstIcon}</div>
							<div className={styles.textWrapper}>
								<h3 className={styles.innerTitle}>
									Это реально работает зимой в Бишкеке?
								</h3>
								<p className={styles.text}>
									Да. Современные модели работают при температурах до –25°C.
									Бишкек подходит по климату.
								</p>
							</div>
						</li>
						<li className={styles.item}>
							<div className={styles.iconWrapper}>{secondIcon}</div>
							<div className={styles.textWrapper}>
								<h3 className={styles.innerTitle}>Сколько это стоит?</h3>
								<p className={styles.text}>
									Зависит от типа системы и площади дома. Ориентир: воздух-вода
									от $3 000, грунт-вода от $7 000. Точная цена — после расчёта.
								</p>
							</div>
						</li>
						<li className={styles.item}>
							<div className={styles.iconWrapper}>{thirdIcon}</div>
							<div className={styles.textWrapper}>
								<h3 className={styles.innerTitle}>
									Чем это лучше газового отопления?
								</h3>
								<p className={styles.text}>
									Не нужно хранить топливо, нет выбросов в доме, предсказуемые
									расходы, автоматическая работа.
								</p>
							</div>
						</li>
						<li className={styles.item}>
							<div className={styles.iconWrapper}>{fourthIcon}</div>
							<div className={styles.textWrapper}>
								<h3 className={styles.innerTitle}>
									Можно ли установить в уже построенный дом?
								</h3>
								<p className={styles.text}>
									Да, но нужна оценка существующей системы. Это покажет
									консультация с инженером.
								</p>
							</div>
						</li>
						<li className={styles.item}>
							<div className={styles.iconWrapper}>{fifthIcon}</div>
							<div className={styles.textWrapper}>
								<h3 className={styles.innerTitle}>Как долго служит?</h3>
								<p className={styles.text}>
									15–25 лет при правильной установке и обслуживании.
								</p>
							</div>
						</li>
						<li className={styles.item}>
							<div className={styles.iconWrapper}>{sixthIcon}</div>
							<div className={styles.textWrapper}>
								<h3 className={styles.innerTitle}>
									Нужно ли специальное обслуживание?
								</h3>
								<p className={styles.text}>
									Минимальное. Раз в год профилактика — проще, чем обслуживание
									газового котла.
								</p>
							</div>
						</li>
						<li className={styles.item}>
							<div className={styles.iconWrapper}>{seventhIcon}</div>
							<div className={styles.textWrapper}>
								<h3 className={styles.innerTitle}>
									Сколько электричества потребляет?
								</h3>
								<p className={styles.text}>
									Тепловой насос потребляет в 3–5 раз меньше электричества, чем
									производит тепла (коэффициент COP).
								</p>
							</div>
						</li>
					</ul>
					<div className={styles.imgWrapper}>
						<Image
							src={img}
							alt=''
							fill
							className={styles.image}
							sizes='(max-width: 1024px) 100vw, 40vw'
						/>
					</div>
				</div>
			</div>
		</div>
	)
}

export default FAQ
